const { ApolloServer, gql } = require('apollo-server');
const { getInvoiceById } = require('./invoiceService'); // Assume this is a secure service to fetch invoices

const typeDefs = gql`
  type Invoice {
    id: ID!
    amount: Float!
    date: String!
    customer: String!
  }

  type Query {
    invoice(id: ID!): Invoice
  }
`;

const resolvers = {
  Query: {
    invoice: async (_, { id }, context) => {
      // Ensure the user is authenticated
      if (!context.user) {
        throw new Error('Unauthorized');
      }

      // Validate the ID format (assuming IDs are UUIDs)
      if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/.test(id)) {
        throw new Error('Invalid ID format');
      }

      // Fetch the invoice securely
      const invoice = await getInvoiceById(id);

      // Check if the invoice exists and belongs to the user
      if (!invoice || invoice.userId !== context.user.id) {
        throw new Error('Invoice not found or access denied');
      }

      return invoice;
    },
  },
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Assuming authentication middleware sets user in context
    return { user: req.user };
  },
});

server.listen().then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
});